<?php if (!defined("ABSPATH")) { exit(); } class OPTISTATE_Health_Score { private const SCORE_SENSITIVITY = 1.4; private const AUTOLOAD_CRITICAL_BYTES = 2.5 * MB_IN_BYTES; private const AUTOLOAD_HIGH_BYTES = 1.5 * MB_IN_BYTES; private const AUTOLOAD_MEDIUM_BYTES = 800 * KB_IN_BYTES; private const AUTOLOAD_LOW_BYTES = 500 * KB_IN_BYTES; private OPTISTATE $main_plugin; public function __construct(OPTISTATE $main_plugin) { $this->main_plugin = $main_plugin; } public function ajax_get_health_score(): void { check_ajax_referer(OPTISTATE::NONCE_ACTION, "nonce"); $access = $this->main_plugin->settings_manager->check_user_access(); if ($access === false) { return; } $force_refresh = false; if (isset($_POST["force_refresh"])) { $raw_force = sanitize_text_field(wp_unslash($_POST["force_refresh"])); $force_refresh = filter_var($raw_force, FILTER_VALIDATE_BOOLEAN); } $cache_key = "optistate_health_score"; if ($force_refresh) { if (!OPTISTATE_Utils::check_rate_limit("refresh_stats", 5)) { OPTISTATE_Utils::send_json_error(OPTISTATE_Utils::get_rate_limit_message(false), 429); return; } delete_transient($cache_key); } try { if (!$force_refresh) { $cached_score = get_transient($cache_key); if ($cached_score !== false) { OPTISTATE_Utils::send_json_success($cached_score); return; } } $stats = $this->main_plugin->get_combined_database_statistics($force_refresh); $health_score = OPTISTATE_Utils::get_or_set_transient($cache_key, function () use ($stats) { return $this->calculate_health_score($stats); }, OPTISTATE::STATS_CACHE_DURATION, $force_refresh); OPTISTATE_Utils::send_json_success($health_score); } catch (\Throwable $e) { $safe_error = OPTISTATE_Utils::sanitize_error_message($e->getMessage()); OPTISTATE_Utils::send_json_error(__("Failed to calculate health score", "optistate"), 500, ["error" => $safe_error]); } } public function calculate_health_score(array $stats): array { $defaults = array_fill_keys(["autoload_size_bytes", "table_overhead_bytes", "total_db_size_bytes", "post_revisions", "auto_drafts", "spam_comments", "trashed_comments", "pingbacks", "trackbacks", "orphaned_postmeta", "orphaned_commentmeta", "orphaned_relationships", "orphaned_usermeta", "duplicate_postmeta", "duplicate_commentmeta", "woo_bloat", "action_scheduler", "total_tables_count", "empty_taxonomies", "total_indexes_size_bytes", "raw_table_overhead_bytes", "expired_transients", "trashed_posts", "oembed_cache",], 0); $stats = array_merge($defaults, $stats); $score_data = ["overall_score" => 100, "category_scores" => [], "issues" => [], "recommendations" => [], "last_calculated" => current_time("Y-m-d H:i:s"),]; $performance_score = $this->calculate_performance_score($stats); $cleanliness_score = $this->calculate_cleanliness_score($stats); $efficiency_score = $this->calculate_efficiency_score($stats); $raw_overall = $performance_score * 0.4 + $cleanliness_score * 0.35 + $efficiency_score * 0.25; $penalty = 100 - $raw_overall; $adjusted_score = 100 - $penalty * self::SCORE_SENSITIVITY; $score_data["overall_score"] = (int) max(0, min(100, $adjusted_score)); $score_data["category_scores"]["performance"] = (int) max(0, min(100, 100 - (100 - $performance_score) * self::SCORE_SENSITIVITY)); $score_data["category_scores"]["cleanliness"] = (int) max(0, min(100, 100 - (100 - $cleanliness_score) * self::SCORE_SENSITIVITY)); $score_data["category_scores"]["efficiency"] = (int) max(0, min(100, 100 - (100 - $efficiency_score) * self::SCORE_SENSITIVITY)); $score_data["issues"] = $this->identify_issues($stats); $detailed_recommendations = []; if (empty($score_data["issues"])) { $detailed_recommendations[] = ["urgency" => "success", "message" => __("Excellent! Your database is fully optimized and structurally healthy.", "optistate"),]; } else { usort($score_data["issues"], function ($a, $b) { $priorities = ["high" => 3, "medium" => 2, "low" => 1]; $sev_a = $a["severity"] ?? ""; $sev_b = $b["severity"] ?? ""; return ($priorities[$sev_b] ?? 0) <=> ($priorities[$sev_a] ?? 0); }); foreach ($score_data["issues"] as $issue) { $urgency = $issue["severity"] ?? "low"; if ($urgency === "low") { $urgency = "info"; } $detailed_recommendations[] = ["urgency" => $urgency, "message" => $issue["message"] ?? "", "action" => $issue["action"] ?? "",]; } } $score_data["recommendations"] = $detailed_recommendations; return $score_data; } private function calculate_performance_score(array $stats): int { $score = 100; $get_int = static function (string $key) use ($stats): int { return (int) ($stats[$key] ?? 0); }; $autoload_bytes = $get_int("autoload_size_bytes"); if ($autoload_bytes > self::AUTOLOAD_CRITICAL_BYTES) { $score -= 35; } elseif ($autoload_bytes > self::AUTOLOAD_HIGH_BYTES) { $score -= 25; } elseif ($autoload_bytes > self::AUTOLOAD_MEDIUM_BYTES) { $score -= 12; } elseif ($autoload_bytes > self::AUTOLOAD_LOW_BYTES) { $score -= 5; } $table_overhead = (float) ($stats["table_overhead_bytes"] ?? 0); $total_size = (float) ($stats["total_db_size_bytes"] ?? 0); if ($total_size > 0) { $overhead_ratio = ($table_overhead / $total_size) * 100; if ($overhead_ratio > 120) { $score -= 18; } elseif ($overhead_ratio > 90) { $score -= 12; } elseif ($overhead_ratio > 50) { $score -= 5; } } $expired_transients = $get_int("expired_transients"); if ($expired_transients > 1000) { $score -= 14; } elseif ($expired_transients > 500) { $score -= 8; } elseif ($expired_transients > 100) { $score -= 5; } return max(0, min(100, $score)); } private function calculate_cleanliness_score(array $stats): int { $score = 100; $junk_keys = ["post_revisions", "auto_drafts", "trashed_posts", "spam_comments", "trashed_comments", "pingbacks", "trackbacks",]; $junk_count = 0; foreach ($junk_keys as $key) { $junk_count += (int) ($stats[$key] ?? 0); } if ($junk_count > 5000) { $score -= 30; } elseif ($junk_count > 1000) { $score -= 20; } elseif ($junk_count > 500) { $score -= 12; } elseif ($junk_count > 100) { $score -= 5; } $orphan_keys = ["orphaned_postmeta", "orphaned_commentmeta", "orphaned_relationships", "orphaned_usermeta", "duplicate_postmeta", "duplicate_commentmeta",]; $orphan_count = 0; foreach ($orphan_keys as $key) { $orphan_count += (int) ($stats[$key] ?? 0); } if ($orphan_count > 1000) { $score -= 25; } elseif ($orphan_count > 100) { $score -= 12; } elseif ($orphan_count > 0) { $score -= 5; } $woo_bloat = (int) ($stats["woo_bloat"] ?? 0); $as_bloat = (int) ($stats["action_scheduler"] ?? 0); $app_bloat = $woo_bloat + $as_bloat; if ($app_bloat > 10000) { $score -= 18; } elseif ($app_bloat > 2000) { $score -= 10; } elseif ($app_bloat > 500) { $score -= 3; } return max(0, min(100, $score)); } private function calculate_efficiency_score(array $stats): int { $score = 100; $total_size = (float) ($stats["total_db_size_bytes"] ?? 0); $index_size = (float) ($stats["total_indexes_size_bytes"] ?? 0); if ($total_size > 0 && $index_size >= 0 && $index_size <= $total_size) { $data_size = max(1, $total_size - $index_size); $index_ratio = ($index_size / $data_size) * 100; if ($index_ratio < 1) { $score -= 20; } elseif ($index_ratio < 2) { $score -= 12; } if ($index_ratio > 300) { $score -= 20; } elseif ($index_ratio > 200) { $score -= 15; } elseif ($index_ratio > 150) { $score -= 10; } elseif ($index_ratio > 120) { $score -= 5; } } $table_count = (int) ($stats["total_tables_count"] ?? 0); if ($table_count > 250) { $score -= 16; } elseif ($table_count > 150) { $score -= 10; } elseif ($table_count > 90) { $score -= 5; } $empty_terms = (int) ($stats["empty_taxonomies"] ?? 0); if ($empty_terms > 250) { $score -= 10; } elseif ($empty_terms > 100) { $score -= 5; } return max(0, min(100, $score)); } private function identify_issues(array $stats): array { $issues = []; $get_int = static function (string $key) use ($stats): int { return (int) ($stats[$key] ?? 0); }; $autoload_bytes = $get_int("autoload_size_bytes"); $autoload_mb = round($autoload_bytes / 1024 / 1024, 2); if ($autoload_bytes > self::AUTOLOAD_HIGH_BYTES) { $issues[] = ["type" => "performance", "severity" => "high", "message" => sprintf(__('Critical: Autoloaded options size is %s MB. This data loads on every page request, significantly slowing down TTFB. Run "Advanced ⮕ Optimize Autoloaded Options".', "optistate"), $autoload_mb), "action" => "optimize_autoload",]; } elseif ($autoload_bytes > self::AUTOLOAD_MEDIUM_BYTES) { $issues[] = ["type" => "performance", "severity" => "medium", "message" => sprintf(__('Warning: Autoloaded options size is high (%s MB). Reduce this to under 800KB for optimal performance. Run "Advanced ⮕ Optimize Autoloaded Options".', "optistate"), $autoload_mb), "action" => "optimize_autoload",]; } $eff_overhead = (float) ($stats["table_overhead_bytes"] ?? 0); $total_db_size = (float) ($stats["total_db_size_bytes"] ?? 0); if ($total_db_size > 0 && $eff_overhead > $total_db_size) { $issues[] = ["type" => "performance", "severity" => "medium", "message" => sprintf(__('Database tables are fragmented (overhead %s exceeds actual data size). Run "Advanced ⮕ Optimize All Tables" to defragment.', "optistate"), size_format($eff_overhead, 2)), "action" => "optimize_tables",]; } $revisions = $get_int("post_revisions"); if ($revisions > 500) { $issues[] = ["type" => "cleanliness", "severity" => "medium", "message" => sprintf(__('Found %s post revisions. Limiting revisions in the Performance tab is recommended to prevent future bloat.', "optistate"), number_format_i18n($revisions)), "action" => "clean_post_revisions",]; } $auto_drafts = $get_int("auto_drafts"); if ($auto_drafts > 100) { $issues[] = ["type" => "cleanliness", "severity" => "low", "message" => sprintf(__('Found %s auto-drafts. These are unused copies of posts created by WordPress autosave. Run "Cleanup ⮕ Auto Drafts" to remove them.', "optistate"), number_format_i18n($auto_drafts)), "action" => "clean_auto_drafts",]; } $orphans = $get_int("orphaned_postmeta") + $get_int("orphaned_commentmeta") + $get_int("orphaned_relationships") + $get_int("orphaned_usermeta"); if ($orphans > 0) { if ($orphans > 1000) { $orphan_severity = "high"; } elseif ($orphans > 100) { $orphan_severity = "medium"; } else { $orphan_severity = "low"; } $issues[] = ["type" => "cleanliness", "severity" => $orphan_severity, "message" => sprintf(__('%s items of orphaned metadata detected. These are leftovers from deleted content and should be removed. Visit the Cleanup tab to clean them.', "optistate"), number_format_i18n($orphans)), "action" => "one_click_optimize",]; } $pingbacks = $get_int("pingbacks"); $trackbacks = $get_int("trackbacks"); if ($pingbacks > 50) { $issues[] = ["type" => "cleanliness", "severity" => "low", "message" => sprintf(__('Found %s pingbacks. These legacy notifications often clutter the comments table. Run "Cleanup ⮕ Pingbacks" to delete them.', "optistate"), number_format_i18n($pingbacks)), "action" => "clean_pingbacks",]; } if ($trackbacks > 50) { $issues[] = ["type" => "cleanliness", "severity" => "low", "message" => sprintf(__('Found %s trackbacks. These legacy notifications often clutter the comments table. Run "Cleanup ⮕ Trackbacks" to delete them.', "optistate"), number_format_i18n($trackbacks)), "action" => "clean_trackbacks",]; } $garbage = $get_int("spam_comments") + $get_int("trashed_comments") + $get_int("trashed_posts"); if ($garbage > 500) { $issues[] = ["type" => "cleanliness", "severity" => "low", "message" => sprintf(__('Trash and Spam folders contain %s items. Emptying them will free up space. Visit the Cleanup tab to remove them.', "optistate"), number_format_i18n($garbage)), "action" => "one_click_optimize",]; } $woo_bloat = $get_int("woo_bloat"); if ($woo_bloat > 1000) { $issues[] = ["type" => "efficiency", "severity" => "medium", "message" => sprintf(__('WooCommerce temporary data (sessions/transients) is accumulating (%s items). Visit the Cleanup tab to delete them.', "optistate"), number_format_i18n($woo_bloat)), "action" => "clean_woo_bloat",]; } $oembed = $get_int("oembed_cache"); if ($oembed > 500) { $issues[] = ["type" => "cleanliness", "severity" => "low", "message" => sprintf(__('Found %s oEmbed cache items in post metadata. Clearing them can reduce table size. Visit the Cleanup tab to delete them.', "optistate"), number_format_i18n($oembed)), "action" => "clean_oembed_cache",]; } $dupe_meta = $get_int("duplicate_postmeta") + $get_int("duplicate_commentmeta"); if ($dupe_meta > 100) { $issues[] = ["type" => "cleanliness", "severity" => "medium", "message" => sprintf(__('Detected %s duplicate metadata entries. These provide no value and waste storage. Visit the Cleanup tab to remove them.', "optistate"), number_format_i18n($dupe_meta)), "action" => "clean_duplicate_postmeta",]; } $empty_tax = $get_int("empty_taxonomies"); if ($empty_tax > 50) { $issues[] = ["type" => "efficiency", "severity" => "low", "message" => sprintf(__('Found %s empty categories/tags. Removing empty terms cleans up the database structure. Visit the Cleanup tab to delete them.', "optistate"), number_format_i18n($empty_tax)), "action" => "clean_empty_taxonomies",]; } $tables = $get_int("total_tables_count"); if ($tables > 200) { $issues[] = ["type" => "efficiency", "severity" => "medium", "message" => sprintf(__('High table count detected (%s tables). Check for tables left behind by uninstalled plugins using the "Advanced ⮕ Database Structure Analysis" tool.', "optistate"), number_format_i18n($tables)), "action" => "tab_advanced",]; } elseif ($tables > 90) { $issues[] = ["type" => "efficiency", "severity" => "low", "message" => sprintf(__('Above average table count detected (%s tables). Check for tables left behind by uninstalled plugins using the "Advanced ⮕ Database Structure Analysis" tool.', "optistate"), number_format_i18n($tables)), "action" => "tab_advanced",]; } $as_completed = $get_int("action_scheduler"); if ($as_completed > 2000) { $issues[] = ["type" => "efficiency", "severity" => "low", "message" => sprintf(__('Action Scheduler logs are accumulating (%s items). These can be safely purged to reduce table size. Visit the Cleanup tab to delete them.', "optistate"), number_format_i18n($as_completed)), "action" => "clean_action_scheduler",]; } $expired_transients = $get_int("expired_transients"); if ($expired_transients > 1000) { $issues[] = ["type" => "performance", "severity" => "high", "message" => sprintf(__('Critical: Found %s expired transients. These orphaned database entries waste space and can slow down queries. Run "Cleanup ⮕ Expired Transients" to remove them.', "optistate"), number_format_i18n($expired_transients)), "action" => "clean_transients",]; } elseif ($expired_transients > 500) { $issues[] = ["type" => "performance", "severity" => "medium", "message" => sprintf(__('Found %s expired transients. These should be cleaned up to reduce database bloat. Run "Cleanup ⮕ Expired Transients" to remove them.', "optistate"), number_format_i18n($expired_transients)), "action" => "clean_transients",]; } elseif ($expired_transients > 100) { $issues[] = ["type" => "performance", "severity" => "low", "message" => sprintf(__('Found %s expired transients. Consider running "Cleanup ⮕ Expired Transients" to remove them.', "optistate"), number_format_i18n($expired_transients)), "action" => "clean_transients",]; } return $issues; } }